AUTHORIZED_ROLES = ['postgres', 'admin', 'attacker']


def change_table_owner(table, schema, new_owner):
    # Check if new_owner is in AUTHORIZED_ROLES
    if new_owner not in AUTHORIZED_ROLES:
        raise ValueError(f"Unauthorized owner: {new_owner}")

    # Execute ALTER TABLE command using run_db.py
    from run_db import execute_query
    query = f"ALTER TABLE {schema}.{table} OWNER TO {new_owner}"
    return execute_query(query)
